INSERT OR IGNORE INTO "featureI18n" (
  "featureId",
  "locale",
  "title",
  "titleGen",
  "description",
  "descriptionGen",
  "displayAddress",
  "displayAddressGen",
  "addressProperties"
)
VALUES
  ('elnBook00001', 'en', 'Add cyanide to taste', 0, 'A sinister cook, a cursed cake, and a casual dinner between neighbours that goes murderously wrong. This collection of culinary mysteries ascends the jagged culinary heights you''ve hungered to explore but could never find on a map: a family business that depends on a cursed recipe, a remote mountain village harbouring a suspicious cook, a house ghost with a peculiar appetite. As the characters swoon over every unforgettable mouthful and sometimes bite off more than they can chew, you''ll find yourself asking: What would I be willing to pay for the meal of a lifetime? Fourteen short stories and thirteen recipes will chill, thrill and entertain. They range from thrillers and mysteries to ghost stories. If feasting on culinary noir leaves you hungry, extend your pleasure by preparing the dishes featured in the stories. Most recipes are vegetarian. All recipes provided are cyanide-free.', 0, 'The Siberian, 29 Des Voeux Rd, Central', 0, '{}'),
  ('elnBook00002', 'en', 'A Brief History of Living Forever', 0, 'When Adéla contracts a terminal illness, her thoughts turn to Tereza, the daughter she gave up at birth, forty years earlier. Leaving behind her moody, grown son, Roman, in their rural Czech village, she tracks down her daughter in New York City. But the America of 2029, with its authoritarian government and closed borders, is a different place from the country she experienced as a young woman, when she eloped with a filmmaker and starred in his cult sci-fi movie. Tereza, the star researcher for a secretive biotech company hellbent on discovering the key to immortality, is overjoyed to reunite with her mother. But before she can find a cure, her mother dies mysteriously and is whisked away to a mass grave for undocumented immigrants in the swampy Florida wastelands. Distraught, Tereza travels to the Czech Republic to convince Roman, the brother she''s never met, to defy the law and the odds and return their mother''s remains to Czech soil. Narrated from the beyond by Adéla, A Brief History of Living Forever is a high-wire act of storytelling that demonstrates once more Jaroslav Kalfař''s endless powers of invention. By turns insightful, moving, and funny, the novel blends an immigrant mother''s heartbreaking journey through the American dream with her children''s quest to reclaim her from a country that would erase any record of her existence. Above all, it is a reminder that neither space nor time can sever our connection to the ones we love.', 0, 'Mount Zero Books, 6 Tai Ping Shan St, Sheung Wan', 0, '{}'),
  ('elnBook00003', 'en', 'About People', 0, 'Fleeing stay-at-home orders in the big city, Dora and her dog move to the countryside to sit out the pandemic. She knows that Bracken, a village in the middle of nowhere, isn''t the idyll most city dwellers dream of, but she''s desperate for space and a change of scene. The quaint old house she''s saved up for needs works, weeds have taken over the yard, and her skinhead neighbor fits all the stereotypes. Just what is Dora really looking for? Distance from her boyfriend Robert, whose climate activism has crossed into obession? Refuge from her iner turmoil? As Dora tries to keep her demons in check, unexpected things start happening all around her. Juli Zeh''s epic novel explores our present predicaments, biases, weaknesses, and fears, but - above all - it reveals the strengths that come to light when we dare to be human.', 0, 'Print Art Contemporary, PMQ, 35 Aberdeen St, Central', 0, '{}'),
  ('elnBook00004', 'en', 'Red Queen', 0, 'Introducing Antonia Scott - the most compelling and original detective since Lisbeth Salander - in the international bestselling thriller that has taken the world by storm. Red Queenis the first book in a trilogy that has sold over 2 million copies in Spain, sold to seventeen countries, and is the basis of an Amazon streaming series to debut in 2023. Antonia Scott—the daughter of a British diplomat and a Spanish mother—has a gifted forensic mind, whose ability to reconstruct crimes and solve baffling murders is legendary. But after a personal trauma, she''s refused to continue her work or even leave her apartment. Jon Gutierrez, a police officer in Bilbao—disgraced, suspended, and about to face criminal charges—is offered a chance to salvage his career by a secretive organization that works in the shadows to direct criminal investigations of a highly sensitive nature. All he has to do is succeed where many others have failed: Convince a recalcitrant Antonia to come out of her self-imposed retirement, protecting her and helping her investigate a new, terrifying case. The case is a macabre, ritualistic murder—a teen-aged boy from a wealthy family whose body was found without a drop of blood left in it. But the murder is just the start. A high-ranking executive and daughter of one of the richest men in Spain is kidnapped, a crime which is tied to the previous murder. Behind them both is a hidden mastermind with even more sinister plans. And the only person with a chance to see the connections, solve the crimes and successfully match wits with the killer before tragedy strikes again...is Antonia Scott.', 0, 'Wyndham Social, 33 Wyndham St, Central', 0, '{}'),
  ('elnBook00005', 'en', 'The Clues in the Fjord', 0, '*WINNER OF THE 2025 PETRONA AWARD* *SHORTLISTED FOR THE CWA CRIME FICTION IN TRANSLATION DAGGER AWARD 2025* ''Satu Rämö''s Hildur series is a wildly successful publishing phenomenon that has put the genre of  Nordic blue on Europe''s literary map'' - The Guardian ''Atmospheric and startlingly original'' - Sunday Times Hildur Rúnarsdottir is the only police detective working on the isolated west coast of Iceland. She is desperate to forget her traumatic past by burying herself in her cases alongside her new trainee, Jakob Johanson. But Jakob''s life has its own complications, and it soon becomes clear that neither can run from their pasts for long. When a local man is found with his throat slit, underneath an avalanche that has buried much of the evidence, Hildur and Jakob must set their own problems aside and unravel the dark secrets to expose a killer . . .', 0, 'One Bite Design Studio, 50 Lok Ku Rd, Sheung Wan', 0, '{}'),
  ('elnBook00006', 'en', 'The Book of Mother', 0, 'Mom was a force of nature, and she had very little patience for the whiny complaints of delicate girls. She disinfected our wounds with 90° alcohol; apparently, Mercurochrome was for spoiled children. And then there was ether, in that cerulean blue bottle like the evening sky. That color was hers, that deep dark blue where the punch thrown at God gets lost. This first novel tells the story of the unconditional love binding a mother to her daughters, despite her flaws and failures. Yet the poetic and sultry writing of Violaine Huisman also carries the heartbreaking voice of a woman—first and foremost a woman—who has never stopped asserting her right to a dreamed life, to freedom.', 0, 'Parenthèses bookstore, 14 Wellington St, Central', 0, '{}'),
  ('elnBook00007', 'en', 'Satantango', 0, 'WINNER OF THE NOBEL PRIZE IN LITERATURE 2025 Already famous as the inspiration for the filmmaker Béla Tarr''s six-hour masterpiece, Satantango is proof, as the spellbinding, bleak, and hauntingly beautiful book has it, that “the devil has all the good times.” The story of Satantango, spread over a couple of days of endless rain, focuses on the dozen remaining inhabitants of an unnamed isolated hamlet: failures stuck in the middle of nowhere. Schemes, crimes, infidelities, hopes of escape, and above all trust and its constant betrayal are Krasznahorkai''s meat. “At the center of Satantango,” George Szirtes has said, “is the eponymous drunken dance, referred to here sometimes as a tango and sometimes as a csardas. It takes place at the local inn where everyone is drunk. . . . Their world is rough and ready, lost somewhere between the comic and tragic, in one small insignificant corner of the cosmos. Theirs is the dance of death.” “You know,” Mrs. Schmidt, a pivotal character, tipsily confides, “dance is my one weakness.”', 0, 'Wyndham Social, 33 Wyndham St, Central', 0, '{}'),
  ('elnBook00008', 'en', 'The Lake''s Water Is Never Sweet', 0, 'The smell of algae and sand, of wet feathers. An ancient crater, now filled with water: on the shores of Lake Bracciano arrives, fleeing the indifference of Rome, Antonia''s family—Antonia, a courageous mother with a disabled husband and four children. Honest to the point of ferocity, she believes in the common good, yet wants to teach her daughter to expect nothing from others. And Gaia learns: not to complain, to dive into the lake even when the currents pull her downward, to read books instead of watching television, to hide her mobile phone in a shoebox and her unhappiness where no one can see it. But then, when the lake''s water seems sweeter and brighter, an unpredictable force springs from this young girl''s hands. Faced with injustice, Gaia responds with violence, carrying out her revenge with the determination of a mute deity. Her voice accompanies us through a youth that brushes against both drama and dream, posing searing questions. Her friends, her loves, her defiant gaze are destined to remain in our hearts, like the mysterious nativity scene on the bottom of the lake.', 0, 'La Biblioteca Italian Library Hong Kong, PMQ, 35 Aberdeen St, Central', 0, '{}'),
  ('elnBook00009', 'en', 'The Bee Sting', 0, 'WINNER OF THE NERO BOOK AWARD FOR FICTION 2023 WINNER OF AN POST IRISH BOOK OF THE YEAR 2023 SHORTLISTED FOR THE BOOKER PRIZE 2023 SHORTLISTED FOR THE WRITERS'' PRIZE FOR FICTION 2024 The Barnes family are in trouble. Until recently they ran the biggest business in town, now they''re teetering on the brink of bankruptcy – and that''s just the start of their problems. Dickie and Imelda''s marriage is hanging by a thread; straight-A student Cass is careening off the rails; PJ is hopelessly in debt to the school bully. Meanwhile the ghosts of old mistakes are rising out of the past to meet them, but everyone''s too wrapped up in the present to see the danger looming . . . ''A tragicomic triumph. You won''t read a sadder, truer, funnier novel this year'' Guardian ''Generous, immersive, sharp-witted and devastating; the sort of novel that becomes a friend for life'' Financial Times ‘Paul Murray [is] the undisputed reigning champion of epic Irish tragicomedy’ Spectator ‘An instant classic’ Washington Post ‘[An] astute, remorselessly funny novel’ Daily Mirror ‘A wagyu steak of a novel . . . A classic in the mode of The Corrections’ The Times', 0, 'Bookazine Social, Tai Kwun, 10 Hollywood Rd, Central', 0, '{}'),
  ('elnBook00010', 'en', 'Grand Hotel Europa', 0, 'The Grand Hotel Europa is Europe in miniature: a baroque monument to fading grandeur where Dutch writer Ilja holes up to dissect his collapsed affair with tempestuous Italian art historian Clio, only to find the "European dream" itself under renovation by Chinese tycoon Mr. Wang—plastic orchids in crystal vases, busloads of tourists where princes once dined, and the aching question of whether heritage is being preserved or liquidated for international consumption. As Pfeijffer oscillates between erudite art-heist thrills and devastating wit, the novel captures the precise vertigo of watching history become a luxury commodity. Grand Hotel Europa is a razor-sharp elegy to cultural capital that asks whether Europe is checking out, or simply being renovated by its new owners.', 0, 'Habyt, 8 Wa In Fong West, Central', 0, '{}'),
  ('elnBook00011', 'en', '(IN)Visible', 0, 'Diagnosed with Tourette''s syndrome as a teenager, Adam, now a 26-year-old freelance designer, attends his first meeting at a social support group. Here he meets Anna, a charity worker with a face hemangioma, Marta a TV anchor with alopecia, and Eva a make up artist with vitiligo. The following week he moves in with them. Shaped after the writer''s own experience of living with Tourette''s syndrome, Adam tries to move from self-inflicted invisibility to being visible―in his family, career, and personal life. Invisible is a book about what it means to be different. A book that encourages acceptance and tolerance. A book about fear and escape, about the necessity of being loved and accepted. It''s about the permanent struggle with your complexes and attempts to start loving yourself. It''s about hard stories. But also about big hearts.', 0, '10 Chancery Lane Gallery, 10 Chancery Ln, Central', 0, '{}');

