INSERT OR IGNORE INTO "featurePropertyI18n" (
  "featureId",
  "propertyId",
  "locale",
  "value",
  "valueGen"
)
VALUES
  ('elnBook00001', 'ZkXV20T2Bsa7', 'en', 'A sinister cook, a cursed cake, and a casual dinner between neighbours that goes murderously wrong. This collection of culinary mysteries ascends the jagged culinary heights you''ve hungered to explore but could never find on a map: a family business that depends on a cursed recipe, a remote mountain village harbouring a suspicious cook, a house ghost with a peculiar appetite. As the characters swoon over every unforgettable mouthful and sometimes bite off more than they can chew, you''ll find yourself asking: What would I be willing to pay for the meal of a lifetime? Fourteen short stories and thirteen recipes will chill, thrill and entertain. They range from thrillers and mysteries to ghost stories. If feasting on culinary noir leaves you hungry, extend your pleasure by preparing the dishes featured in the stories. Most recipes are vegetarian. All recipes provided are cyanide-free.', 0),
  ('elnBook00001', 'w7L3$qPA41ij', 'en', 'Karmen Špiljak is an award-winning author of suspense, horror and speculative fiction, a developmental editor and an Author Accelerator certified book coach for fiction. Her thriller, ''No Such Thing as Goodbye'', was shortlisted and received an honourable mention on ''The Black Spring Crime Fiction Prize 2020''. Her short story collection, ''Add Cyanide to Taste'', won the 2022 IndieReader Discovery Award for best short stories. In 2023, LeVar Burton Reads licensed her short story, ''Three Roses'', for their podcast. Her collection, ''Pass the Cyanide'', won ''The 2023 Wishing Shelf Awards Bronze''. She currently lives in Belgrade with her husband, two cats and an unknown number of fictional characters.', 0),
  ('elnBook00001', 'K0ceBm5NQFlF', 'en', 'Rachel Smith is an artist, storyteller and educator. She comes from a rural farming community where life had a very different focus than what she has lived iun the past 20 years as an immigrant to Hong Kong. In her studio in Sham Shui Po, Smith works with paper, fabric and watercolour. Inspired by her love and occasional despair of the city she lives and works in, the scenes outside her studio window push her art in directions that are at turns comforting and alarming. Smith seeks to express in simple forms. As time passes and the city rapidly changes further Smith waits with her scissors and brushes to see what will emerge slicing away, leaving room for light and movement. In response to the lack of face to face classes during the time of Covid, the HK Mail Art Club came into being - a weekly mail out of DIY art kits to do at home. The kits invite you to assemble, colour and construct paper based figures, while learning about the natural world. When not at the studio, I am podcasting, storytelling and organising Hong Kong Stories, directiing the Hong kong Spoken Word Festival, or taking miniaturised versions of real people on adventures with Tiny Trekkers Travel Agency.', 0),
  ('elnBook00002', 'ZkXV20T2Bsa7', 'en', 'When Adéla contracts a terminal illness, her thoughts turn to Tereza, the daughter she gave up at birth, forty years earlier. Leaving behind her moody, grown son, Roman, in their rural Czech village, she tracks down her daughter in New York City. But the America of 2029, with its authoritarian government and closed borders, is a different place from the country she experienced as a young woman, when she eloped with a filmmaker and starred in his cult sci-fi movie. Tereza, the star researcher for a secretive biotech company hellbent on discovering the key to immortality, is overjoyed to reunite with her mother. But before she can find a cure, her mother dies mysteriously and is whisked away to a mass grave for undocumented immigrants in the swampy Florida wastelands. Distraught, Tereza travels to the Czech Republic to convince Roman, the brother she''s never met, to defy the law and the odds and return their mother''s remains to Czech soil. Narrated from the beyond by Adéla, A Brief History of Living Forever is a high-wire act of storytelling that demonstrates once more Jaroslav Kalfař''s endless powers of invention. By turns insightful, moving, and funny, the novel blends an immigrant mother''s heartbreaking journey through the American dream with her children''s quest to reclaim her from a country that would erase any record of her existence. Above all, it is a reminder that neither space nor time can sever our connection to the ones we love.', 0),
  ('elnBook00002', 'w7L3$qPA41ij', 'en', 'Jaroslav Kalfař was born one year before the Velvet Revolution in Prague, Czech Republic. He immigrated to the United States at the age of fifteen and learned the English language through novels and cartoons. He has earned an MFA from New York University, where he was a Goldwater Fellow and a nominee for the inaugural E.L. Doctorow Prize. His debut novel, Spaceman of Bohemia, was a finalist for the Center for Fiction First Novel Prize, and has been translated into nine languages. He lives in Brooklyn.', 0),
  ('elnBook00002', 'K0ceBm5NQFlF', 'en', 'Ellie Law (羅正心) is an actress and a graduate of the School of Drama at The Hong Kong Academy for Performing Arts, majoring in Acting, with additional training in stage performance in Boston, USA. She graduated in 2020 and has since appeared in productions including Quills, Sweet Madarin(and its revival), Come Out! – A Physical Cabaret. Her stage credits at the Academy includes Spring Awakening, RENT and more, and she received a nomination for Outstanding Actress at the 11th ''The Hong Kong Theatre Libre'' for her role as Ilse in Spring Awakening.', 0),
  ('elnBook00003', 'ZkXV20T2Bsa7', 'en', 'Fleeing stay-at-home orders in the big city, Dora and her dog move to the countryside to sit out the pandemic. She knows that Bracken, a village in the middle of nowhere, isn''t the idyll most city dwellers dream of, but she''s desperate for space and a change of scene. The quaint old house she''s saved up for needs works, weeds have taken over the yard, and her skinhead neighbor fits all the stereotypes. Just what is Dora really looking for? Distance from her boyfriend Robert, whose climate activism has crossed into obession? Refuge from her iner turmoil? As Dora tries to keep her demons in check, unexpected things start happening all around her. Juli Zeh''s epic novel explores our present predicaments, biases, weaknesses, and fears, but - above all - it reveals the strengths that come to light when we dare to be human.', 0),
  ('elnBook00003', 'w7L3$qPA41ij', 'en', 'Juli Zeh studied law in Passau and Leipzig, and holds a doctorate in international law from the University of Saarbrücken. She is one of Germany''s most successful authors of both literary thrillers and novels. Her debut novel EAGLES AND ANGELS was an international bestseller and won the Deutscher Book Prize, since which time her books have been translated into 35 languages. She has been awarded myriad prizes for her work, including the Carl Amery Literature Prize, the Thomas Mann Prize, and teh German Order of Merit.', 0),
  ('elnBook00003', 'K0ceBm5NQFlF', 'en', 'Wong Yi is an award-winning Hong Kong writer, librettist, radio show host, and a founding member of Xi Xi Foundation. In 2020, she was named one of 20 Young Sinophone Novelists to Watch by the Taiwanese literary magazine Unitas. She is the author of four short story collections: Ways To Love In A Crowded City (2021), The Four Seasons of Lam Yip (2019), Patched Up (2015), and News Stories (2010). She was the Hong Kong Writer-in-residence for Hong Kong Baptist University''s first Chinese Writers Workshop in 2021, Writer-in-residence for Hong Kong Education University in 2023, and has participated in events such as the Singapore Writers Festival, Singapore Book Fair, Hong Kong International Literary Festival, and Taipei International Book Exhibition. In 2023, she participated in the University of Iowa''s International Writing Program Fall Residency.', 0),
  ('elnBook00004', 'ZkXV20T2Bsa7', 'en', 'Introducing Antonia Scott - the most compelling and original detective since Lisbeth Salander - in the international bestselling thriller that has taken the world by storm. Red Queenis the first book in a trilogy that has sold over 2 million copies in Spain, sold to seventeen countries, and is the basis of an Amazon streaming series to debut in 2023. Antonia Scott—the daughter of a British diplomat and a Spanish mother—has a gifted forensic mind, whose ability to reconstruct crimes and solve baffling murders is legendary. But after a personal trauma, she''s refused to continue her work or even leave her apartment. Jon Gutierrez, a police officer in Bilbao—disgraced, suspended, and about to face criminal charges—is offered a chance to salvage his career by a secretive organization that works in the shadows to direct criminal investigations of a highly sensitive nature. All he has to do is succeed where many others have failed: Convince a recalcitrant Antonia to come out of her self-imposed retirement, protecting her and helping her investigate a new, terrifying case. The case is a macabre, ritualistic murder—a teen-aged boy from a wealthy family whose body was found without a drop of blood left in it. But the murder is just the start. A high-ranking executive and daughter of one of the richest men in Spain is kidnapped, a crime which is tied to the previous murder. Behind them both is a hidden mastermind with even more sinister plans. And the only person with a chance to see the connections, solve the crimes and successfully match wits with the killer before tragedy strikes again...is Antonia Scott.', 0),
  ('elnBook00004', 'w7L3$qPA41ij', 'en', 'Juan Gómez-Jurado (December 1977 Madrid, Spain) is an award winning journalist and bestselling author. He is one of the three most successful contemporary Spanish authors along with New York Times bestselling authors Javier Sierra and Carlos Ruiz Zafón. In 2016, Juan celebrated the mark of 6 million readers worldwide. Juan is the author of nine international bestselling novels: GOD''S SPY, THE MOSES EXPEDITION, THE TRAITOR''S EMBLEM, THE LEGEND OF THE THIEF, SCAR, RED QUEEN, BLACK WOLF and WHITE KING. They have been translated into more than 40 languages. He is also the author of the young adult science-fiction series, ALEX COLT SPACE CADET. uan is an avid reader and traveller. He lives in Spain with Sam, his bad behaviored dog.', 0),
  ('elnBook00004', 'K0ceBm5NQFlF', 'en', 'Billy Chan combines his Hong Kong roots with an upbringing in Guatemala and Canada to bring a multicultural perspective to Spanish language education. For the past two decades, he has dedicated himself to the promotion of Spanish language and culture in Hong Kong. Billy currently serves as the Director of Spanish World HK, the first and only Spanish language learning centre in Hong Kong accredited by Instituto Cervantes. The centre features a resource library to support student learning, and Billy is currently working on expanding this facility with the aim of establishing a hub for Spanish literature enthusiasts in Hong Kong.', 0),
  ('elnBook00005', 'ZkXV20T2Bsa7', 'en', '*WINNER OF THE 2025 PETRONA AWARD* *SHORTLISTED FOR THE CWA CRIME FICTION IN TRANSLATION DAGGER AWARD 2025* ''Satu Rämö''s Hildur series is a wildly successful publishing phenomenon that has put the genre of  Nordic blue on Europe''s literary map'' - The Guardian ''Atmospheric and startlingly original'' - Sunday Times Hildur Rúnarsdottir is the only police detective working on the isolated west coast of Iceland. She is desperate to forget her traumatic past by burying herself in her cases alongside her new trainee, Jakob Johanson. But Jakob''s life has its own complications, and it soon becomes clear that neither can run from their pasts for long. When a local man is found with his throat slit, underneath an avalanche that has buried much of the evidence, Hildur and Jakob must set their own problems aside and unravel the dark secrets to expose a killer . . .', 0),
  ('elnBook00005', 'w7L3$qPA41ij', 'en', 'Satu Rämö is a Finnish-Icelandic author and an entrepreneur in communications. She holds a Master of Science in Economics and a Bachelor of Arts. She was the top-selling Finnish author in 2023, with her HILDUR detective series selling almost 330,000 copies. As of September 2024, the publishing rights for the HILDUR series had been sold to 17 countries, including Germany, France, the Nordics and the  UK. Rämö lives with her Icelandic spouse and their two children in Ísafjörður, Iceland', 0),
  ('elnBook00006', 'ZkXV20T2Bsa7', 'en', 'Mom was a force of nature, and she had very little patience for the whiny complaints of delicate girls. She disinfected our wounds with 90° alcohol; apparently, Mercurochrome was for spoiled children. And then there was ether, in that cerulean blue bottle like the evening sky. That color was hers, that deep dark blue where the punch thrown at God gets lost. This first novel tells the story of the unconditional love binding a mother to her daughters, despite her flaws and failures. Yet the poetic and sultry writing of Violaine Huisman also carries the heartbreaking voice of a woman—first and foremost a woman—who has never stopped asserting her right to a dreamed life, to freedom.', 0),
  ('elnBook00006', 'w7L3$qPA41ij', 'en', 'Violaine Huisman, born in 1979, is a French writer known for her impactful storytelling. Her debut novel, The Book of Mother, received critical acclaim, winning the Prix Françoise Sagan and earning a longlisting for the International Booker Prize. Through her evocative prose, Huisman explores complex themes of family, love, and personal identity, establishing herself as a significant voice in contemporary literature.', 0),
  ('elnBook00006', 'K0ceBm5NQFlF', 'en', 'Angela Yu (born 2003) is a poet born and raised in Hong Kong. At 17 years old she published her first poetry collection in Chinese but now writes primarily in English and French. She is the author of 不反叛通知書, Juvie, Psycho in Paradise, and L''encyclopédie des parasites. Her work deals mainly with the banality of modern existence and its many effects. Angela''s new books, 60 km/h and Point d''interrogation, are scheduled to be published in mid-2026. As an aspiring linguist and translator, she spends most of her free time maintaining the ten languages that she speaks.', 0),
  ('elnBook00007', 'ZkXV20T2Bsa7', 'en', 'WINNER OF THE NOBEL PRIZE IN LITERATURE 2025 Already famous as the inspiration for the filmmaker Béla Tarr''s six-hour masterpiece, Satantango is proof, as the spellbinding, bleak, and hauntingly beautiful book has it, that “the devil has all the good times.” The story of Satantango, spread over a couple of days of endless rain, focuses on the dozen remaining inhabitants of an unnamed isolated hamlet: failures stuck in the middle of nowhere. Schemes, crimes, infidelities, hopes of escape, and above all trust and its constant betrayal are Krasznahorkai''s meat. “At the center of Satantango,” George Szirtes has said, “is the eponymous drunken dance, referred to here sometimes as a tango and sometimes as a csardas. It takes place at the local inn where everyone is drunk. . . . Their world is rough and ready, lost somewhere between the comic and tragic, in one small insignificant corner of the cosmos. Theirs is the dance of death.” “You know,” Mrs. Schmidt, a pivotal character, tipsily confides, “dance is my one weakness.”', 0),
  ('elnBook00007', 'w7L3$qPA41ij', 'en', 'Born in Gyula, Hungary, in 1954, László Krasznahorkai is celebrated for his dystopian and melancholic novels that delve deeply into human existence. Often described as postmodern, his work has earned him numerous distinctions, including the 2013 Best Translated Book Award in Fiction for Satantango, the 2019 National Book Award for Translated Literature, the 2015 Man Booker International Prize, and the 2024 Prix Formentor for lifetime achievement. László Krasznahorkai received the 2025 Nobel Prize in Literature “for his compelling and visionary oeuvre that, in the midst of apocalyptic terror, reaffirms the power of art”. His writing, translated into over forty languages, has gained global acclaim. Several of his novels, including Satantango and The Melancholy of Resistance, have been adapted into acclaimed feature films directed by Béla Tarr, further extending the reach of his unique literary vision.', 0),
  ('elnBook00007', 'K0ceBm5NQFlF', 'en', 'VULGO Theatre Attila Gönczy is a talented Hungarian actor residing in Hong Kong, and the visionary founder of both Aurelian Academy and VULGO Theatre. Established in 2023, VULGO Theatre is a Hong Kong-based company, dedicating to captivating audiences through performances that explore the depths of human emotion and creativity. Their shows invite viewers to immerse in unique stories, blending innovative staging with powerful acting.', 0),
  ('elnBook00008', 'ZkXV20T2Bsa7', 'en', 'The smell of algae and sand, of wet feathers. An ancient crater, now filled with water: on the shores of Lake Bracciano arrives, fleeing the indifference of Rome, Antonia''s family—Antonia, a courageous mother with a disabled husband and four children. Honest to the point of ferocity, she believes in the common good, yet wants to teach her daughter to expect nothing from others. And Gaia learns: not to complain, to dive into the lake even when the currents pull her downward, to read books instead of watching television, to hide her mobile phone in a shoebox and her unhappiness where no one can see it. But then, when the lake''s water seems sweeter and brighter, an unpredictable force springs from this young girl''s hands. Faced with injustice, Gaia responds with violence, carrying out her revenge with the determination of a mute deity. Her voice accompanies us through a youth that brushes against both drama and dream, posing searing questions. Her friends, her loves, her defiant gaze are destined to remain in our hearts, like the mysterious nativity scene on the bottom of the lake.', 0),
  ('elnBook00008', 'w7L3$qPA41ij', 'en', 'Giulia Caminito is an Italian writer, born in Rome in 1988. She made her debut with La grande A (2016), followed by Un giorno verrà (2019), which was shortlisted for the Premio Strega. Her novel L''acqua del lago non è mai dolce (2021) won the Premio Campiello and established her as one of the most distinctive voices in contemporary Italian literature. Her writing often explores social inequality, family ties, and the tensions between place, class, and personal ambition.', 0),
  ('elnBook00008', 'K0ceBm5NQFlF', 'en', 'Elizabeth Chung Yi-Lei (or just “Lilli”) is a PhD Candidate at CUHK researching Hong Kong Literature, focussing on the relationship between community and contemporary literature. Both a critic and creative writer, her works have been published digitally and physically, and can be found in Where Else: An International Hong Kong Poetry Anthology and The Signal House Edition, amongst others. Her most recent work is as primary editor of Peel Street Poetry 20th Anniversary Anthology, which will be launched during the 2026 HKILF. Chung is a co-organiser of the Hong Kong poetry groups Peel Street Poetry and OutLoudHK隨言香港, and a co-founder of the new literary group Flow State留言, which welcomes performances of any literature and aims to highlight original English and Cantonese writings from the city. Online @chungyilei.', 0),
  ('elnBook00009', 'ZkXV20T2Bsa7', 'en', 'WINNER OF THE NERO BOOK AWARD FOR FICTION 2023 WINNER OF AN POST IRISH BOOK OF THE YEAR 2023 SHORTLISTED FOR THE BOOKER PRIZE 2023 SHORTLISTED FOR THE WRITERS'' PRIZE FOR FICTION 2024 The Barnes family are in trouble. Until recently they ran the biggest business in town, now they''re teetering on the brink of bankruptcy – and that''s just the start of their problems. Dickie and Imelda''s marriage is hanging by a thread; straight-A student Cass is careening off the rails; PJ is hopelessly in debt to the school bully. Meanwhile the ghosts of old mistakes are rising out of the past to meet them, but everyone''s too wrapped up in the present to see the danger looming . . . ''A tragicomic triumph. You won''t read a sadder, truer, funnier novel this year'' Guardian ''Generous, immersive, sharp-witted and devastating; the sort of novel that becomes a friend for life'' Financial Times ‘Paul Murray [is] the undisputed reigning champion of epic Irish tragicomedy’ Spectator ‘An instant classic’ Washington Post ‘[An] astute, remorselessly funny novel’ Daily Mirror ‘A wagyu steak of a novel . . . A classic in the mode of The Corrections’ The Times', 0),
  ('elnBook00009', 'w7L3$qPA41ij', 'en', 'Paul Murray is an Irish novelist. He studied English literature at Trinity College, Dublin and has written two novels: An Evening of Long Goodbyes (shortlisted for the Whitbread Prize in 2003, and nominated for the Kerry Irish Fiction Award) and Skippy Dies (longlisted for the 2010 Booker Prize and the 2010 Bollinger Everyman Wodehouse Award for comic fiction).', 0),
  ('elnBook00009', 'K0ceBm5NQFlF', 'en', 'Dr. Moonyoung Hong is Assistant Professor in the School of English at the University of Hong Kong. She obtained her MPhil in Irish Writing and PhD in English at Trinity College Dublin. She is author of Tom Murphy''s Theatre of Everyday Space (Routledge, 2025) and co-editor of The Irish Pub: Invention and Re-invention (Cork University Press, 2025). She has published in Irish Studies Review, Comparative Drama, Études Irlandaises, and Review of Irish Studies in Europe (RISE). She is on the executive committee for the Irish Society for Theatre Research (ISTR).', 0),
  ('elnBook00010', 'ZkXV20T2Bsa7', 'en', 'The Grand Hotel Europa is Europe in miniature: a baroque monument to fading grandeur where Dutch writer Ilja holes up to dissect his collapsed affair with tempestuous Italian art historian Clio, only to find the "European dream" itself under renovation by Chinese tycoon Mr. Wang—plastic orchids in crystal vases, busloads of tourists where princes once dined, and the aching question of whether heritage is being preserved or liquidated for international consumption. As Pfeijffer oscillates between erudite art-heist thrills and devastating wit, the novel captures the precise vertigo of watching history become a luxury commodity. Grand Hotel Europa is a razor-sharp elegy to cultural capital that asks whether Europe is checking out, or simply being renovated by its new owners.', 0),
  ('elnBook00010', 'w7L3$qPA41ij', 'en', 'Ilja Leonard Pfeijffer (b. 1968) is one of the most celebrated contemporary writers in the Dutch language. A poet, novelist, playwright, essayist and columnist, he has published over forty titles across genres and is renowned for his powerful style, classical mastery of form, and sharp engagement with contemporary society. His work often explores the tension between fact and fiction, identity and reality, combining literary playfulness with political and cultural reflection. Pfeijffer achieved international acclaim with the novel La Superba (2013) and later with Grand Hotel Europa (2018), a bestselling novel on love, mass tourism, European identity and the end of an era, translated into more than twenty languages. Trained as a classicist and holding a PhD from Leiden University, Pfeijffer now lives and works in Genoa, Italy. He is one of the very few Dutch authors to have won major prizes for both poetry and prose, including the Libris Literature Prize, the VSB Poetry Prize, and the Belgian Boon Prize for Literature.', 0),
  ('elnBook00010', 'K0ceBm5NQFlF', 'en', 'Often mistaken for a synthetic lifeform, Mart is a cyberspace native, magical pony whisperer, and digital humanist. Came to Hong Kong chasing those who''d seen C-beams glitter near the Tannhäuser Gate. Stayed for the future that was already here. Author of immersive cosmic stories performed under starlight. His Linguistics M.Phil has bloomed into a lifelong love of the ways humans speak. A cartographer by day, he maps the intangible weave of the city. At night he convenes the Chronoscopy SF book club and moonlights as a frenetic anarchivist. Confidently clears CAPTCHAs.', 0),
  ('elnBook00011', 'ZkXV20T2Bsa7', 'en', 'Diagnosed with Tourette''s syndrome as a teenager, Adam, now a 26-year-old freelance designer, attends his first meeting at a social support group. Here he meets Anna, a charity worker with a face hemangioma, Marta a TV anchor with alopecia, and Eva a make up artist with vitiligo. The following week he moves in with them. Shaped after the writer''s own experience of living with Tourette''s syndrome, Adam tries to move from self-inflicted invisibility to being visible―in his family, career, and personal life. Invisible is a book about what it means to be different. A book that encourages acceptance and tolerance. A book about fear and escape, about the necessity of being loved and accepted. It''s about the permanent struggle with your complexes and attempts to start loving yourself. It''s about hard stories. But also about big hearts.', 0),
  ('elnBook00011', 'w7L3$qPA41ij', 'en', 'Ivan Baidak is a bold Ukrainian fiction writer and poet whose debut novel, Personally Me Personally for You (2013), became a national bestseller and received widespread critical acclaim. His short story collections, Role Plays (2014) and The Shadows of Our Dates (2017), also dominated bookstore bestseller lists. He later authored the socially charged novel Invisible, exploring themes of inclusion and difference, which was named one of the best books of the year by PEN Ukraine. The work inspired a theater production and several photo exhibitions dedicated to its subject matter. Baidak''s writing is distinguished by its sharp psychological depth, vivid imagery, and masterful command of language. Set against realistic contemporary backdrops, his stories infuse everyday lives with philosophical reflection and raw emotional power. He frequently experiments with narrative form, playfully bending structure, plot, and textual rhythm to create innovative literary experiences.', 0),
  ('elnBook00011', 'K0ceBm5NQFlF', 'en', 'Mocha（莫家欣） is a Hong Kong based freelance actress, drama teacher, dubbing actor and Arts Administration practitioner. She graduated from the Hong Kong Academy for Performing Arts majoring in Acting. She also obtained a Bachelor Degree from Baptist University, majoring in Public Relations and Advertising, and minoring in Humanities. As an theatre actress, she has work with vary theatre companies including Hong Kong Arts Festival, Theatre du pif, Hong Kong Repertory Theatre, On and on theatre workshop, Fantasy Puppet theatre etc. Recent performance includes “Crime and Punishment” (Hong Kong Arts Festival) & “The Three Sisters” (Theatre du pif).', 0);
